
package com.example.taxgap.controller; import com.example.taxgap.domain.entity.ExceptionRecord; import com.example.taxgap.service.ExceptionService; import org.springframework.http.ResponseEntity; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/exceptions") public class ExceptionController { private final ExceptionService service; public ExceptionController(ExceptionService s){service=s;} @GetMapping @PreAuthorize("hasAnyRole('ADMIN','AUDITOR')") public ResponseEntity<List<ExceptionRecord>> list(@RequestParam(required=false) String customerId, @RequestParam(required=false) String severity, @RequestParam(required=false) String ruleName){ return ResponseEntity.ok(service.getAll(customerId, severity, ruleName)); } }
